worked_example.final_code:
import java.net.http.*;
import java.net.URI;
import java.time.Duration;
import java.util.*;
import com.fasterxml.jackson.databind.*;
import com.fasterxml.jackson.databind.node.*;

public class StockDashboard {
    // Production pattern: singletons
    private static final HttpClient HTTP = HttpClient.newBuilder()
        .connectTimeout(Duration.ofSeconds(10))
        .build();
    private static final ObjectMapper MAPPER = new ObjectMapper();

    // Simulate what a real GET response looks like:
    static String simulateQuote(String symbol) {
        Map<String, String> data = Map.of(
            "TCS",      "{\"symbol\":\"TCS\",\"price\":3890,\"changePercent\":4.1}",
            "RELIANCE", "{\"symbol\":\"RELIANCE\",\"price\":2450,\"changePercent\":1.2}",
            "INFY",     "{\"symbol\":\"INFY\",\"price\":1560,\"changePercent\":-3.8}"
        );
        return data.getOrDefault(symbol, null);  // null = 404
    }

    static void fetchQuote(String symbol) throws Exception {
        String mockBody = simulateQuote(symbol);
        int mockStatus = mockBody != null ? 200 : 404;

        // In real code: HttpResponse<String> response = HTTP.send(request, ...)
        System.out.printf("[GET /quotes/%s] → HTTP %d%n", symbol, mockStatus);
        if (mockStatus == 200) {
            JsonNode json = MAPPER.readTree(mockBody);
            System.out.printf("  %-12s ₹%,.0f  %+.1f%%%n",
                json.path("symbol").asText(),
                json.path("price").asDouble(),
                json.path("changePercent").asDouble());
        } else {
            System.out.println("  " + symbol + ": Symbol not found");
        }
    }

    static void createWatchlist(String name, List<String> symbols) throws Exception {
        ObjectNode body = MAPPER.createObjectNode();
        body.put("name", name);
        ArrayNode syms = MAPPER.createArrayNode();
        symbols.forEach(syms::add);
        body.set("symbols", syms);

        String requestJson = MAPPER.writeValueAsString(body);
        System.out.printf("%n[POST /watchlists]%n  Body: %s%n  → HTTP 201 Created%n",
            requestJson);
    }

    public static void main(String[] args) throws Exception {
        System.out.println("=== Stock Dashboard ===");
        for (String sym : new String[]{"TCS", "RELIANCE", "INFY", "WIPRO"}) {
            fetchQuote(sym);
        }
        createWatchlist("My Portfolio", List.of("TCS", "RELIANCE"));
    }
}

